WITH RECURSIVE category_tree AS ( -- 1. 初始查询（锚点）：找到顶层节点 SELECT id FROM course_categories WHERE id = #{categoryId}
UNION ALL
-- 2. 递归查询：连接自身，找到下一层子节点 SELECT c.id FROM course_categories c INNER JOIN category_tree ct ON c.parent_id = ct.id ) -- 3. 从递归结果中查询所有ID SELECT id FROM category_tree
